import { useState, useEffect } from "react";
import AdminLayout, { AP, PageHeader, Card, Badge, Btn, Table, Modal } from "../../components/admin/AdminLayout";
import { adminService } from "../../services/adminService";
import "../../styles/pages/admin/AdminCommon.css";

const STATUSES = ["", "CONFIRMED", "PENDING_PAYMENT", "CANCELLED", "COMPLETED"];
const STATUS_LABEL = {
  "": "Tất cả",
  CONFIRMED:       "Đã xác nhận",
  PENDING_PAYMENT: "Chờ thanh toán",
  CANCELLED:       "Đã hủy",
  COMPLETED:       "Hoàn thành",
};

function fmt(n) {
  if (!n && n !== 0) return "—";
  return Number(n).toLocaleString("vi-VN") + " ₫";
}

export default function AdminBookings({ navigate, user, onLogout }) {
  const [bookings, setBookings] = useState([]);
  const [filter, setFilter]     = useState("");
  const [loading, setLoading]   = useState(true);
  const [detail, setDetail]     = useState(null);
  const [search, setSearch]     = useState("");
  const [page, setPage] = useState(1);
  const pageSize = 10;

  const load = async (status = filter) => {
    setLoading(true);
    const data = await adminService.getBookings(status);
    setBookings(data);
    setLoading(false);
  };

  useEffect(() => { load(); }, []);
  const handleFilter = s => { setFilter(s); load(s); };

  const filtered = bookings.filter(b => {
    if (!search) return true;
    const q = search.toLowerCase();
    return (b.userEmail || "").toLowerCase().includes(q) || (b.hotelName || "").toLowerCase().includes(q);
  });

  const counts = {
    total:          bookings.length,
    confirmed:      bookings.filter(b => b.status === "CONFIRMED").length,
    pending:        bookings.filter(b => b.status === "PENDING_PAYMENT").length,
    cancelled:      bookings.filter(b => b.status === "CANCELLED").length,
    revenue:        bookings.filter(b => b.status === "CONFIRMED" || b.status === "COMPLETED")
                            .reduce((s, b) => s + (Number(b.totalPrice) || 0), 0),
  };

  return (
    <AdminLayout page="admin-bookings" navigate={navigate} user={user} onLogout={onLogout}>
      <PageHeader title="Quản lý đặt phòng" subtitle="Theo dõi tất cả giao dịch đặt phòng trong hệ thống" />

      {/* Summary */}
      <div className="admin-summary-grid admin-summary-grid-5">
        {[
          { label: "Tổng đặt phòng",    value: counts.total,        color: "#4361ee", icon: "📋" },
          { label: "Đã xác nhận",       value: counts.confirmed,    color: "#2e7d32", icon: "✅" },
          { label: "Chờ thanh toán",    value: counts.pending,      color: "#f57f17", icon: "⏳" },
          { label: "Đã hủy",            value: counts.cancelled,    color: "#888",    icon: "❌" },
          { label: "Doanh thu xác nhận",value: fmt(counts.revenue), color: AP,        icon: "💰", isStr: true },
        ].map(c => (
          <div key={c.label} className="admin-summary-card">
            <span className="admin-summary-card-icon">{c.icon}</span>
            <div>
              <div className="admin-summary-card-value" style={{ fontSize: c.isStr ? 14 : 22, color: c.color }}>{c.value}</div>
              <div className="admin-summary-card-label">{c.label}</div>
            </div>
          </div>
        ))}
      </div>

      <Card>
        <div className="admin-table-toolbar">
          <div className="admin-table-toolbar-left">
            {STATUSES.map(s => (
              <button
                key={s}
                onClick={() => handleFilter(s)}
                className={`admin-filter-tab${filter === s ? " active" : ""}`}
                style={{ padding: "6px 14px" }}
              >
                {STATUS_LABEL[s]}
              </button>
            ))}
          </div>
          <input
            value={search}
            onChange={e => setSearch(e.target.value)}
            placeholder="🔍 Tìm email, khách sạn..."
            className="admin-table-search"
          />
        </div>

        {loading ? (
          <div className="admin-loading">Đang tải dữ liệu...</div>
        ) : (
          <>
            <Table
              headers={["#ID", "Người dùng", "Khách sạn", "Nhận phòng", "Trả phòng", "Số đêm", "Tổng tiền", "Trạng thái", ""]}
              rows={filtered.slice((page - 1) * pageSize, page * pageSize).map(b => [
              <span className="admin-cell-id">#{b.id}</span>,
              <span className="admin-cell-text">{b.userEmail}</span>,
              <span className="admin-cell-name">{b.hotelName || "—"}</span>,
              <span className="admin-cell-text">{b.checkIn}</span>,
              <span className="admin-cell-text">{b.checkOut}</span>,
              <span className="admin-cell-text">{b.nights} đêm</span>,
              <span className="admin-cell-amount">{fmt(b.totalPrice)}</span>,
              <Badge status={b.status} />,
              <Btn small variant="action" onClick={() => setDetail(b)}>Chi tiết</Btn>,
            ])}
              empty="Không có đặt phòng nào"
            />

            {/* Pagination */}
            {filtered.length > pageSize && (
              <div className="admin-pagination">
                {[...Array(Math.ceil(filtered.length / pageSize))].map((_, i) => (
                  <button
                    key={i}
                    onClick={() => { setPage(i + 1); window.scrollTo({ top: 0, behavior: "smooth" }); }}
                    className={`admin-page-btn${page === i + 1 ? " active" : ""}`}
                  >
                    {i + 1}
                  </button>
                ))}
              </div>
            )}
          </>
        )}
      </Card>

      {/* Detail modal */}
      {detail && (
        <Modal title={`📋 Chi tiết đặt phòng #${detail.id}`} onClose={() => setDetail(null)}>
          <div className="admin-modal-info">
            <div className="admin-modal-info-title">{detail.hotelName || "—"}</div>
            <div className="admin-modal-info-sub">{detail.userEmail}</div>
          </div>
          {[
            ["Ngày nhận phòng", detail.checkIn],
            ["Ngày trả phòng",  detail.checkOut],
            ["Số đêm",          `${detail.nights} đêm`],
            ["Tổng tiền",       fmt(detail.totalPrice)],
            ["Ngày đặt",        detail.createdAt],
            ["Trạng thái",      <Badge status={detail.status} />],
          ].map(([k, v]) => (
            <div key={k} className="admin-modal-row">
              <span className="admin-modal-row-key">{k}</span>
              <span className="admin-modal-row-val">{v}</span>
            </div>
          ))}
          <div className="admin-modal-actions-right">
            <Btn variant="ghost" onClick={() => setDetail(null)}>Đóng</Btn>
          </div>
        </Modal>
      )}
    </AdminLayout>
  );
}

import { useState, useEffect } from "react";
import AdminLayout, {
  AP, PageHeader, Card, Badge, Btn, Table, Modal, FormField,
} from "../../components/admin/AdminLayout";
import { adminService } from "../../services/adminService";
import { Clock, CheckCircle, XCircle } from "lucide-react";
import { useToast } from "../../contexts/ToastContext";
import { SkeletonRow } from "../../components/ui/Skeleton";
import "../../styles/pages/admin/AdminCommon.css";

const STATUSES = ["", "PENDING", "APPROVED", "REJECTED"];
const STATUS_LABEL = { "": "Tất cả", PENDING: "Chờ duyệt", APPROVED: "Đã duyệt", REJECTED: "Từ chối" };

export default function AdminPartners({ navigate, user, onLogout }) {
  const [apps, setApps]         = useState([]);
  const [filter, setFilter]     = useState("");
  const [loading, setLoading]   = useState(true);
  const [error, setError]       = useState("");
  const [rejectModal, setRejectModal] = useState(null);
  const [rejectReason, setRejectReason] = useState("");
  const [acting, setActing]     = useState(null);
  const [detailModal, setDetailModal] = useState(null);
  const [page, setPage] = useState(1);
  const pageSize = 10;
  const toast = useToast();

  const load = async (status = filter) => {
    setLoading(true); setError("");
    try {
      const data = await adminService.getPartnerApplications(status || null);
      setApps(Array.isArray(data) ? data : []);
    } catch (e) { setError(e.message); }
    finally { setLoading(false); }
  };

  useEffect(() => { load(); }, []);

  const handleFilter = s => { setFilter(s); load(s); };

  const handleApprove = async id => {
    if (!window.confirm("Phê duyệt đơn đăng ký này?")) return;
    setActing(id);
    try { 
      await adminService.approvePartner(id); 
      toast.success("Đã phê duyệt đối tác thành công!");
      await load(); 
    }
    catch (e) { toast.error(e.message); }
    setActing(null);
  };

  const handleReject = async () => {
    if (!rejectReason.trim()) { toast.warning("Vui lòng nhập lý do từ chối"); return; }
    setActing(rejectModal.id);
    try {
      await adminService.rejectPartner(rejectModal.id, rejectReason);
      toast.success("Đã từ chối đơn đăng ký.");
      setRejectModal(null); setRejectReason("");
      await load();
    } catch (e) { toast.error(e.message); }
    setActing(null);
  };

  const counts = {
    pending:  apps.filter(a => a.status === "PENDING").length,
    approved: apps.filter(a => a.status === "APPROVED").length,
    rejected: apps.filter(a => a.status === "REJECTED").length,
  };

  return (
    <AdminLayout page="admin-partners" navigate={navigate} user={user} onLogout={onLogout}>
      <PageHeader title="Quản lý đối tác" subtitle="Xem xét và phê duyệt đơn đăng ký trở thành đối tác" />

      {/* Summary */}
      <div className="admin-summary-grid admin-summary-grid-3">
        {[
          { label: "Chờ duyệt", value: counts.pending,  icon: <Clock size={24} color={AP} /> },
          { label: "Đã duyệt",  value: counts.approved, icon: <CheckCircle size={24} color={AP} /> },
          { label: "Từ chối",   value: counts.rejected, icon: <XCircle size={24} color={AP} /> },
        ].map(c => (
          <div key={c.label} className="admin-summary-card">
            <div className="admin-summary-card-icon">{c.icon}</div>
            <div>
              <div className="admin-summary-card-value">{c.value}</div>
              <div className="admin-summary-card-label">{c.label}</div>
            </div>
          </div>
        ))}
      </div>

      <Card>
        {/* Filter tabs */}
        <div className="admin-filter-bar" style={{ marginBottom: 20 }}>
          {STATUSES.map(s => (
            <button
              key={s}
              onClick={() => handleFilter(s)}
              className={`admin-filter-tab${filter === s ? " active" : ""}`}
            >
              {STATUS_LABEL[s]}
              {s === "PENDING" && counts.pending > 0 && (
                <span className="admin-filter-tab-badge">{counts.pending}</span>
              )}
            </button>
          ))}
        </div>

        {error && <div className="admin-error-alert">⚠️ {error}</div>}

        {loading ? (
          <Table
            headers={["#ID", "Tên doanh nghiệp", "Email", "Số điện thoại", "Trạng thái", "Thao tác"]}
            rows={Array.from({ length: 5 }).map((_, i) => [
              <SkeletonRow key={i} cols={6} />
            ])}
          />
        ) : (
          <>
            <Table
              headers={["#ID", "Tên doanh nghiệp", "Email", "Số điện thoại", "Trạng thái", "Thao tác"]}
              rows={apps.slice((page - 1) * pageSize, page * pageSize).map(a => [
              <span className="admin-cell-id">#{a.id}</span>,
              <div className="admin-cell-name">{a.bussinessName || a.businessName || "—"}</div>,
              <span className="admin-cell-text">{a.email || "—"}</span>,
              <span className="admin-cell-text">{a.phoneNumber || "—"}</span>,
              <Badge status={a.status} />,
              <div className="admin-cell-actions">
                <Btn small variant="action" onClick={() => setDetailModal(a)}>👁 Xem</Btn>
                {a.status === "PENDING" && (
                  <>
                    <Btn small variant="success" loading={acting === a.id} onClick={() => handleApprove(a.id)}>Duyệt</Btn>
                    <Btn small variant="danger" loading={acting === a.id} onClick={() => { setRejectModal({ id: a.id }); setRejectReason(""); }}>Từ chối</Btn>
                  </>
                )}
              </div>,
            ])}
              empty="Không có đơn đăng ký nào"
            />

            {/* Pagination */}
            {apps.length > pageSize && (
              <div className="admin-pagination">
                {[...Array(Math.ceil(apps.length / pageSize))].map((_, i) => (
                  <button
                    key={i}
                    onClick={() => { setPage(i + 1); window.scrollTo({ top: 0, behavior: "smooth" }); }}
                    className={`admin-page-btn${page === i + 1 ? " active" : ""}`}
                  >
                    {i + 1}
                  </button>
                ))}
              </div>
            )}
          </>
        )}
      </Card>

      {/* Detail modal */}
      {detailModal && (
        <Modal title="Chi tiết đơn đăng ký đối tác" onClose={() => setDetailModal(null)}>
          {[
            ["ID", `#${detailModal.id}`],
            ["Tên doanh nghiệp", detailModal.bussinessName || detailModal.businessName || "—"],
            ["Email", detailModal.email || "—"],
            ["Số điện thoại", detailModal.phoneNumber || "—"],
            ["Trạng thái", <Badge status={detailModal.status} />],
          ].map(([k, v]) => (
            <div key={k} className="admin-modal-row">
              <span className="admin-modal-row-key">{k}</span>
              <span className="admin-modal-row-val">{v}</span>
            </div>
          ))}
          {detailModal.status === "PENDING" && (
            <div className="admin-modal-actions">
              <Btn variant="danger" onClick={() => { setDetailModal(null); setRejectModal({ id: detailModal.id }); }}>❌ Từ chối</Btn>
              <Btn variant="success" onClick={() => { setDetailModal(null); handleApprove(detailModal.id); }}>✅ Phê duyệt</Btn>
            </div>
          )}
          {detailModal.status !== "PENDING" && (
            <div className="admin-modal-actions-right">
              <Btn variant="ghost" onClick={() => setDetailModal(null)}>Đóng</Btn>
            </div>
          )}
        </Modal>
      )}

      {/* Reject modal */}
      {rejectModal && (
        <Modal title="❌ Từ chối đơn đăng ký" onClose={() => setRejectModal(null)}>
          <p style={{ fontSize: 13, color: "#555", marginBottom: 14 }}>Vui lòng nhập lý do từ chối để thông báo cho đối tác.</p>
          <FormField label="Lý do từ chối" required>
            <textarea
              value={rejectReason}
              onChange={e => setRejectReason(e.target.value)}
              placeholder="Nhập lý do từ chối..."
              rows={4}
              className="admin-textarea"
            />
          </FormField>
          <div className="admin-modal-actions" style={{ marginTop: 8 }}>
            <Btn variant="ghost" onClick={() => setRejectModal(null)}>Hủy</Btn>
            <Btn variant="danger" disabled={acting === rejectModal.id} onClick={handleReject}>
              {acting === rejectModal.id ? "Đang xử lý..." : "Xác nhận từ chối"}
            </Btn>
          </div>
        </Modal>
      )}
    </AdminLayout>
  );
}

