import { useState, useEffect } from "react";
import AdminLayout, {
  AP, PageHeader, Card, Btn, SearchInput, Table, Modal,
} from "../../components/admin/AdminLayout";
import { adminService } from "../../services/adminService";
import { Star, Trash2, Eye } from "lucide-react";

function StarRating({ rating, size = 14 }) {
  return (
    <div style={{ display: "flex", gap: 2, alignItems: "center" }}>
      {[1, 2, 3, 4, 5].map(n => (
        <Star
          key={n}
          size={size}
          fill={n <= rating ? "#f59e0b" : "none"}
          color={n <= rating ? "#f59e0b" : "#ddd"}
        />
      ))}
      <span style={{ fontSize: 12, color: "#888", marginLeft: 4, fontWeight: 600 }}>{rating}/5</span>
    </div>
  );
}

const RATING_OPTIONS = ["", "5", "4", "3", "2", "1"];
const RATING_LABEL   = { "": "Tất cả", "5": "⭐⭐⭐⭐⭐", "4": "⭐⭐⭐⭐", "3": "⭐⭐⭐", "2": "⭐⭐", "1": "⭐" };

export default function AdminReviews({ navigate, user, onLogout }) {
  const [reviews, setReviews]       = useState([]);
  const [search, setSearch]         = useState("");
  const [ratingFilter, setRating]   = useState("");
  const [loading, setLoading]       = useState(true);
  const [error, setError]           = useState("");
  const [deleting, setDeleting]     = useState(null);
  const [detailModal, setDetail]    = useState(null);
  const [page, setPage] = useState(1);
  const pageSize = 10;

  const load = async () => {
    setLoading(true); setError("");
    try {
      const data = await adminService.getReviews();
      setReviews(Array.isArray(data) ? data : []);
    } catch (e) { setError(e.message); }
    finally { setLoading(false); }
  };

  useEffect(() => { load(); }, []);

  const handleDelete = async (id) => {
    if (!window.confirm("Xoá đánh giá này? Điểm trung bình của khách sạn sẽ được cập nhật lại.")) return;
    setDeleting(id);
    try {
      await adminService.deleteReview(id);
      setReviews(prev => prev.filter(r => r.id !== id));
    } catch (e) { alert(e.message); }
    setDeleting(null);
  };

  const filtered = reviews.filter(r => {
    const matchSearch = !search ||
      r.hotelName?.toLowerCase().includes(search.toLowerCase()) ||
      r.userEmail?.toLowerCase().includes(search.toLowerCase());
    const matchRating = !ratingFilter || String(r.rating) === ratingFilter;
    return matchSearch && matchRating;
  });

  const counts = {
    total: reviews.length,
    avg: reviews.length
      ? (reviews.reduce((s, r) => s + r.rating, 0) / reviews.length).toFixed(1)
      : "—",
    fivestar: reviews.filter(r => r.rating === 5).length,
    onestar:  reviews.filter(r => r.rating === 1).length,
  };

  return (
    <AdminLayout page="admin-reviews" navigate={navigate} user={user} onLogout={onLogout}>
      <PageHeader
        title="Quản lý đánh giá"
        subtitle="Xem và xoá đánh giá khách sạn từ người dùng"
      />

      {/* Summary cards */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 14, marginBottom: 24 }}>
        {[
          { label: "Tổng đánh giá", value: counts.total,   icon: "⭐", color: "#f59e0b" },
          { label: "Điểm TB",       value: counts.avg,     icon: "📊", color: "#4361ee" },
          { label: "5 sao",         value: counts.fivestar, icon: "🌟", color: "#2e7d32" },
          { label: "1 sao",         value: counts.onestar,  icon: "😞", color: "#c62828" },
        ].map(c => (
          <div key={c.label} style={{
            background: "#fff", borderRadius: 12, padding: "16px 20px",
            boxShadow: "0 2px 10px rgba(0,0,0,0.05)", border: "1px solid #f0f0f0",
            display: "flex", alignItems: "center", gap: 14,
          }}>
            <div style={{
              width: 48, height: 48, borderRadius: "50%", background: `${c.color}18`,
              display: "flex", alignItems: "center", justifyContent: "center", fontSize: 22,
            }}>
