source:
import { useState, useEffect } from "react";
import { partnerService } from "../../services/partnerService";
import { PageHeader, Card, Badge, Btn, Table, Modal } from "../../components/admin/AdminLayout";
import { 
  ChevronLeft, ChevronRight, Calendar as CalendarIcon, 
  MapPin, Building2, CheckCircle2, Clock, AlertCircle, 
  Info, Search, MoreHorizontal, User, ClipboardList,
  RefreshCcw, DollarSign, XCircle, Filter, HelpCircle
} from "lucide-react";
import "../../styles/pages/PartnerCalendar.css";

// --- Constants ---
const DAY_NAMES = ["CN", "T2", "T3", "T4", "T5", "T6", "T7"];
const MONTH_NAMES = ["Tháng Một", "Tháng Hai", "Tháng Ba", "Tháng Tư", "Tháng Năm", "Tháng Sáu", 
                     "Tháng Bảy", "Tháng Tám", "Tháng Chín", "Tháng Mười", "Tháng Mười Một", "Tháng Mười Hai"];

const TABS = [
  { key: "CALENDAR", label: "Lịch & Trạng thái", icon: CalendarIcon },
  { key: "REFUNDS",  label: "Quản lý Hoàn tiền", icon: RefreshCcw },
];

// --- Helpers ---
function buildCalendarDays(year, month) {
  const first = new Date(year, month, 1).getDay();
  const total = new Date(year, month + 1, 0).getDate();
  const days = [];
  for (let i = 0; i < first; i++) days.push(null);
  for (let d = 1; d <= total; d++) days.push(d);
  return days;
}

function buildBookingSet(bookings, year, month) {
  const occupied = new Map();
  for (const b of bookings) {
    if (b.status === "CANCELLED") continue;
    const ci = new Date(b.checkIn);
    const co = new Date(b.checkOut);
    const cur = new Date(ci);
    while (cur < co) {
      if (cur.getFullYear() === year && cur.getMonth() === month) {
        const d = cur.getDate();
        if (!occupied.has(d)) occupied.set(d, []);
        occupied.get(d).push(b);
      }
      cur.setDate(cur.getDate() + 1);
    }
  }
  return occupied;
}

const STATUS_MAP = {
  CONFIRMED: { bg: "#ecfdf5", color: "#10b981", label: "Xác nhận" },
  PENDING_PAYMENT: { bg: "#fffbeb", color: "#f59e0b", label: "Chờ TT" },
  CANCELLED: { bg: "#f8fafc", color: "#94a3b8", label: "Đã hủy" },
  COMPLETED: { bg: "#FFF1F2", color: "#BE1E2E", label: "Hoàn thành" },
};

function fmt(n) {
  if (!n && n !== 0) return "—";
  return Number(n).toLocaleString("vi-VN") + " ₫";
}

import { MOCK_CALENDAR_BOOKINGS, MOCK_PARTNER_REFUNDS } from "../../data/mockData";

export default function PartnerCalendar() {
  const [activeTab, setActiveTab] = useState("CALENDAR");
  const now = new Date();
  const [year, setYear]   = useState(now.getFullYear());
  const [month, setMonth] = useState(now.getMonth());
  const [hotels, setHotels]   = useState([]);
  const [selectedHotel, setSelectedHotel] = useState(null);
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading]   = useState(false);
  const [refunds, setRefunds]   = useState(MOCK_PARTNER_REFUNDS);
  const [refundDetail, setRefundDetail] = useState(null);
  const [acting, setActing]     = useState(null);
  const [page, setPage]         = useState(1);
  const pageSize = 8;

  useEffect(() => {
    partnerService.getMyHotels()
      .then(d => {
        const list = Array.isArray(d) ? d : [];
        setHotels(list);
        if (list.length > 0) setSelectedHotel(list[0]);
      })
      .catch(() => {});
  }, []);

  useEffect(() => {
    if (!selectedHotel || activeTab !== "CALENDAR") return;
    setLoading(true);
    const from = `${year}-${String(month + 1).padStart(2, "0")}-01`;
    const lastDay = new Date(year, month + 1, 0).getDate();
    const to   = `${year}-${String(month + 1).padStart(2, "0")}-${lastDay}`;

    partnerService.getBookings({ hotelId: selectedHotel.id, checkInFrom: from, checkInTo: to, size: 100 })
      .then(d => setBookings(d?.items?.length ? d.items : MOCK_CALENDAR_BOOKINGS))
      .catch(() => setBookings(MOCK_CALENDAR_BOOKINGS))
      .finally(() => setLoading(false));
  }, [selectedHotel, year, month, activeTab]);

  function prevMonth() {
    if (month === 0) { setYear(y => y - 1); setMonth(11); }
    else setMonth(m => m - 1);
  }
  function nextMonth() {
    if (month === 11) { setYear(y => y + 1); setMonth(0); }
    else setMonth(m => m + 1);
  }

  const days       = buildCalendarDays(year, month);
  const occupied   = buildBookingSet(bookings, year, month);
  const today      = now.getFullYear() === year && now.getMonth() === month ? now.getDate() : -1;

  const handleRefundAction = async (id, newStatus) => {
    const label = newStatus === "APPROVED" ? "PHÊ DUYỆT" : "TỪ CHỐI";
    if (!window.confirm(`Xác nhận ${label} yêu cầu hoàn tiền này?`)) return;
    setActing(id);
    await new Promise(r => setTimeout(r, 800));
    setRefunds(prev => prev.map(r => r.id === id ? { ...r, status: newStatus } : r));
    if (refundDetail?.id === id) setRefundDetail(d => ({ ...d, status: newStatus }));
    setActing(null);
  };

  return (
    <div style={{ paddingBottom: 80 }}>
      <PageHeader 
        title="Quản lý Vận hành & Lịch" 
        subtitle="Quản lý chi tiết lịch trống, giá niêm yết và các yêu cầu hoàn tiền tập trung" 
      />

      {/* Modern Tabs */}
      <div style={{ display: "flex", gap: 12, marginBottom: 32, background: "#fff", padding: "8px", borderRadius: 20, border: "1px solid #f1f5f9", width: "fit-content", boxShadow: "0 2px 8px rgba(0,0,0,0.04)" }}>
        {TABS.map(t => (
          <button
            key={t.key}
            onClick={() => setActiveTab(t.key)}
            style={{
              display: "flex", alignItems: "center", gap: 10, padding: "12px 24px", borderRadius: 16, border: "none",
              background: activeTab === t.key ? "#BE1E2E" : "transparent",
              color: activeTab === t.key ? "#fff" : "#64748b",
              fontWeight: 800, fontSize: 14, cursor: "pointer", transition: "all 0.3s cubic-bezier(0.4, 0, 0.2, 1)",
              boxShadow: activeTab === t.key ? "0 4px 12px rgba(190, 30, 46, 0.3)" : "none"
            }}
          >
            <t.icon size={18} />
            {t.label}
          </button>
        ))}
      </div>

      {activeTab === "CALENDAR" ? (
        <section>
          {/* Summary Row */}
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 20, marginBottom: 32 }}>
            {[
              { label: "TỔNG ĐƠN HÀNG", value: bookings.length, Icon: ClipboardList, color: "#BE1E2E", bg: "#FFF1F2" },
              { label: "DỰ KIẾN CHECK-IN", value: bookings.filter(b => b.status === "CONFIRMED").length, Icon: CheckCircle2, color: "#10b981", bg: "#ecfdf5" },
              { label: "CHỜ THANH TOÁN", value: bookings.filter(b => b.status === "PENDING_PAYMENT").length, Icon: Clock, color: "#f59e0b", bg: "#fffbeb" },
              { label: "YÊU CẦU HOÀN", value: refunds.filter(r => r.status === "PENDING").length, Icon: RefreshCcw, color: "#ef4444", bg: "#fef2f2" },
            ].map((s, i) => (
              <div key={i} style={{ 
                background: "#fff", borderRadius: 24, padding: "24px", border: "1px solid #f1f5f9", 
                boxShadow: "0 1px 3px rgba(0,0,0,0.05)", display: "flex", alignItems: "center", gap: 20
              }}>
                <div style={{ width: 52, height: 52, borderRadius: 16, background: s.bg, display: "flex", alignItems: "center", justifyContent: "center" }}>
                  <s.Icon size={26} color={s.color} />
                </div>
                <div>
                  <div style={{ fontSize: 12, fontWeight: 800, color: "#94a3b8", letterSpacing: 0.5, marginBottom: 4 }}>{s.label}</div>
                  <div style={{ fontSize: 24, fontWeight: 900, color: "#1e293b" }}>{s.value}</div>
                </div>
              </div>
            ))}
          </div>

          {/* Control Bar */}
          <div style={{ 
            background: "#fff", borderRadius: 24, padding: "24px 32px", marginBottom: 32, 
            display: "flex", flexWrap: "wrap", gap: 32, alignItems: "center", justifyContent: "space-between",
            border: "1px solid #f1f5f9", boxShadow: "0 1px 3px rgba(0,0,0,0.05)"
          }}>
            <div style={{ display: "flex", alignItems: "center", gap: 16 }}>
              <div style={{ fontSize: 15, fontWeight: 800, color: "#475569", whiteSpace: "nowrap" }}>CHỌN CƠ SỞ:</div>
              <div style={{ position: "relative" }}>
                <Building2 size={18} color="#94a3b8" style={{ position: "absolute", left: 16, top: "50%", transform: "translateY(-50%)" }} />
                <select
                  style={{ padding: "12px 20px 12px 48px", border: "1px solid #e2e8f0", borderRadius: 16, fontSize: 15, outline: "none", background: "#f8fafc", cursor: "pointer", fontWeight: 700, minWidth: 380, color: "#1e293b" }}
                  value={selectedHotel?.id || ""}
                  onChange={e => setSelectedHotel(hotels.find(h => String(h.id) === e.target.value) || null)}
                >
                  {hotels.length === 0 && <option>Chưa có khách sạn</option>}
                  {hotels.map(h => <option key={h.id} value={h.id}>{h.name}</option>)}
                </select>
              </div>
            </div>

            <div style={{ display: "flex", alignItems: "center", gap: 12, background: "#f8fafc", padding: "10px", borderRadius: 18, border: "1px solid #e2e8f0" }}>
              <button onClick={prevMonth} style={navBtnSt}><ChevronLeft size={20} /></button>
              <div style={{ display: "flex", alignItems: "center", gap: 12, minWidth: 240, justifyContent: "center" }}>
                <CalendarIcon size={20} color="#BE1E2E" />
                <span style={{ fontSize: 18, fontWeight: 900, color: "#1e293b", letterSpacing: 0.5 }}>
                  {MONTH_NAMES[month].toUpperCase()} {year}
                </span>
              </div>
              <button onClick={nextMonth} style={navBtnSt}><ChevronRight size={20} /></button>
            </div>
          </div>

          {/* Calendar Grid */}
          <div style={{ background: "#fff", borderRadius: 32, padding: "40px", border: "1px solid #f1f5f9", boxShadow: "0 1px 3px rgba(0,0,0,0.05)" }}>
            {loading ? (
              <div style={{ textAlign: "center", padding: 120, color: "#94a3b8" }}>
                <div className="partner-calendar-loading">
                  <div className="partner-calendar-spinner" />
                  Đang đồng bộ dữ liệu vận hành...
                </div>
              </div>
            ) : (
              <>
                <div className="partner-calendar-grid">
                  {DAY_NAMES.map(d => (
                    <div key={d} className="partner-calendar-day-header">{d}</div>
                  ))}
                </div>

                <div className="partner-calendar-days-grid">
                  {days.map((d, i) => {
                    if (!d) return <div key={`empty-${i}`} className="partner-calendar-empty-cell" />;
                    const dayBookings = occupied.get(d) || [];
                    const isToday     = d === today;
                    const isPast      = new Date(year, month, d) < new Date(now.getFullYear(), now.getMonth(), now.getDate());

                    return (
                      <div key={d} 
                        className="partner-calendar-cell"
                        style={{
                          "--cell-bg": isToday ? "#FFF1F2" : isPast ? "#f8fafc" : "#fff",
                          "--cell-border": isToday ? "2px solid #BE1E2E" : "1px solid #f1f5f9"
                        }}
                      >
                        <div style={{ 
                          fontSize: 20, fontWeight: 900, 
                          color: isToday ? "#BE1E2E" : isPast ? "#cbd5e1" : "#1e293b",
                          marginBottom: 16
                        }}>
                          {d}
                        </div>

                        <div style={{ display: "flex", flexDirection: "column", gap: 8, flex: 1 }}>
                          {dayBookings.slice(0, 3).map((b, idx) => (
                            <div key={idx} style={{ 
                              fontSize: 11, fontWeight: 800, padding: "5px 10px", borderRadius: 10,
                              background: STATUS_MAP[b.status]?.bg || "#f1f5f9",
                              color: STATUS_MAP[b.status]?.color || "#475569",
                              whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
                              display: "flex", alignItems: "center", gap: 6, border: "1px solid rgba(0,0,0,0.03)"
                            }}>
                              <User size={12} /> {b.customerName}
                            </div>
                          ))}
                          {dayBookings.length > 3 && (
                            <div style={{ fontSize: 11, color: "#94a3b8", fontWeight: 800, textAlign: "center", marginTop: 4, background: "#f8fafc", borderRadius: 8, padding: "2px 0" }}>
                              +{dayBookings.length - 3} khách khác
                            </div>
                          )}
