// --- Helpers ---
function fmtPrice(n) {
  if (n >= 1_000_000_000) return (n / 1_000_000_000).toFixed(1) + " tỷ ₫";
  if (n >= 1_000_000)     return (n / 1_000_000).toFixed(1) + " tr ₫";
  return new Intl.NumberFormat("vi-VN").format(n) + " ₫";
}

const STATUS_LABELS = {
  CONFIRMED:       { label: "Đã xác nhận", color: "#10b981", bg: "#ecfdf5", border: "#b91c1c" },
  PENDING_PAYMENT: { label: "Chờ thanh toán", color: "#f59e0b", bg: "#fffbeb", border: "#b45309" },
  CANCELLED:       { label: "Đã hủy", color: "#94a3b8", bg: "#f8fafc", border: "#64748b" },
  COMPLETED:       { label: "Hoàn thành", color: "#BE1E2E", bg: "#FFF1F2", border: "#991B1B" },
};

// --- Sparkline Mini-Chart ---
function Sparkline({ color = "#BE1E2E", data = [30, 45, 35, 55, 40, 60, 50] }) {
  const width = 80;
  const height = 30;
  const points = data.map((d, i) => {
    const x = (i * width) / (data.length - 1);
    const y = height - (d * height) / 100;
    return `${x},${y}`;
  }).join(" ");

  return (
    <svg width={width} height={height} style={{ overflow: "visible" }}>
      <polyline
        fill="none"
        stroke={color}
        strokeWidth="2.5"
        strokeLinejoin="round"
        strokeLinecap="round"
        points={points}
      />
    </svg>
  );
}

