  const confirmedAll = bookings.filter(b => b.status === "CONFIRMED" || b.status === "COMPLETED");
  const cancelledAll = bookings.filter(b => b.status === "CANCELLED");

  const years = [...new Set(
    Object.keys(grouped).map(k => k.slice(0, 4)).filter(Boolean)
  )].sort().reverse();
