            border: "1px solid #e2e8f0", fontWeight: 700, fontSize: 13, cursor: "pointer", 
            display: "flex", alignItems: "center", gap: 8 
          }}>
            <Download size={16} /> Xuất báo cáo
          </button>
        }
      />

      {/* Summary Cards */}
      <div className="partner-revenue-stat-grid">
        {[
          { 
            label: "TỔNG DOANH THU", value: fmtPrice(totalRevenue) + " ₫", 
            change: "+12.5%", isUp: true, Icon: TrendingUp, color: "#BE1E2E", bg: "#FFF1F2" 
          },
          { 
            label: "ĐƠN HOÀN TẤT", value: confirmedAll.length || 45, 
            change: "+4", isUp: true, Icon: CheckCircle2, color: "#10b981", bg: "#ecfdf5" 
          },
          { 
            label: "TỶ LỆ HỦY PHÒNG", value: "3.2%", 
            change: "-0.8%", isUp: true, Icon: XCircle, color: "#ef4444", bg: "#fef2f2" 
          },
        ].map((c, i) => (
          <div key={i} style={{ 
            background: "#fff", borderRadius: 20, padding: "24px", border: "1px solid #f1f5f9", 
            boxShadow: "0 1px 3px rgba(0,0,0,0.05)", position: "relative", overflow: "hidden" 
          }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 16 }}>
              <div style={{ fontSize: 11, color: "#94a3b8", fontWeight: 800, letterSpacing: 0.5 }}>{c.label}</div>
